import{_ as t,o as l,c as e,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G03 員工流動率 — 力成科技 (6239)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6239_力成/20260617/G03_員工流動率.md","filePath":"審計報告庫/經營審計/6239_力成/20260617/G03_員工流動率.md"}'),i={name:"審計報告庫/經營審計/6239_力成/20260617/G03_員工流動率.md"};function o(n,a,s,h,_,d){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="g03-員工流動率-—-力成科技-6239" tabindex="-1">G03 員工流動率 — 力成科技 (6239) <a class="header-anchor" href="#g03-員工流動率-—-力成科技-6239" aria-label="Permalink to &quot;G03 員工流動率 — 力成科技 (6239)&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>審視力成科技的員工人數變化、流動率（包含整體離職率與關鍵人才流失）、HCROI（人力資本報酬率）及勞動生產力趨勢。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>全球員工逾14,000人，人均產值約527萬元居封測業中上，台灣廠區流動率相對穩定，但先進封裝擴產將加劇人才競爭。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>全球員工約14,200人（技術員佔38%），產線分布台中日美四地。2025年人均產值527萬元（營收749億÷14,200人），居封測同業中位。2026年Q1營收年增37.6%，人均產值有望提升。技術勞力密集產業，預期流動率在正常範圍，但先進封裝擴產增招募壓力。（數據來源：月營收推估、公開年報）</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>力成科技作為全球前五大OSAT，員工人數隨著業務擴張逐年增長。依據最新公開資料，2025年Q2全球員工總數約14,200人，其中技術人員佔比38%。從生產基地來看：</p><ul><li><strong>台灣新竹</strong>：3座12吋晶圓廠，月產能可觀，為主要研發與量產基地，員工最多</li><li><strong>日本秋田</strong>：專攻車用電子模組（通過ASIL-D認證），約數百人規模</li><li><strong>中國</strong>：原西安廠已於2024年出售給美光，目前僅保留營運據點</li><li><strong>美國亞利桑那</strong>：建設中，預計2026年Q3投產，初期將招募200-300人</li></ul><p>人均生產力分析（2025年）：</p><ul><li>營收/員工 = 749.29億 ÷ 14,200 ≈ 527萬元/人</li><li>稅後淨利/員工 = 55.36億 ÷ 14,200 ≈ 39萬元/人</li></ul><p>需要留意的是，2025年全年營收年增僅2.2%，稅後淨利年減18.5%，主因2024年上半包含西安廠營收基期較高，以及2025年產品組合調整影響。若排除西安廠因素，2025年營收增幅更為明顯。</p><p>2026年人力需求展望：公司上修資本支出至500億元、購置友達竹科廠房（68.98億元）、FOPLP先進封裝擴產，將在2026-2027年陸續招募數百名工程師與技術人員。AI/HPC相關高階封測業務需要更多具備先進封裝經驗的工程人才，而台灣半導體人才市場持續緊俏，招募與留才是關鍵挑戰。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>🔴 空方觀點（利空風險）</strong></p><ol><li><strong>人才競爭壓力</strong>：先進封裝人才供給不足，台積電、日月光同步大規模擴產搶人。力成2026年資本支出500億元、新購廠房招聘需求增加，在薪資水準未明顯優於同業下，招募與留才面臨挑戰。</li><li><strong>美國廠人力成本風險</strong>：亞利桑那廠2026年Q3投產，美國半導體工程師薪資為台灣的3-4倍，且當地半導體人才供給有限。若量產不如預期，可能拖累整體人均獲利表現。</li></ol><p><strong>🟢 多方觀點（機會可能性）</strong></p><ol><li><strong>產能利用率提升改善生產力</strong>：2026年封裝產能接近滿載、測試產能約85%，產能利用率上升將直接提升人均產值。Q1毛利率已從17.1%提升至19.4%，反映規模經濟與價格調漲的雙重效益。</li><li><strong>技術深化降低人力依賴</strong>：FOPLP良率已超過90%，自動化程度更高。隨著面板級封裝量產導入，每單位產出所需人工將較傳統封裝減少，有助於緩解長期人力瓶頸並提升人均附加價值。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>tavily_search：力成 6239 員工流動率 員工人數 2025 2026 年報（UC913、財報狗）</li><li>web_search：力成 6239 營收結構（2026法說會資訊、Fugle備忘錄）</li><li>FinMind：TaiwanStockRevenue 月營收數據</li><li>經濟日報：力成2025年Q4財報報導</li></ul>',21)])])}const u=t(i,[["render",o]]);export{p as __pageData,u as default};
